app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD') or 'your-email-password'

db = SQLAlchemy(app)
mail = Mail(app)

# Secure token serializer
serializer = URLSafeTimedSerializer(app.config['SECRET_KEY'])

# User Model
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(128))
    reset_token = db.Column(db.String(100))
    token_expires = db.Column(db.DateTime)

    def set_password(self, password):
        self.password_hash = bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')

    def check_password(self, password):
        return bcrypt.checkpw(password.encode('utf-8'), self.password_hash.encode('utf-8'))

# Routes
@app.route('/reset-password', methods=['GET', 'POST'])
def reset_password():
    if request.method == 'POST':
        email = request.form['email']
        user = User.query.filter_by(email=email).first()

        if not user:
            flash('No account found with that email.')
            return redirect(url_for('reset_password'))

        # Generate token
        user.reset_token = serializer.dumps(email, salt='password-reset-salt')
        user.token_expires = datetime.utcnow() + timedelta(hours=1)
        db.session.commit()

        # Send email
        try:
            msg = Message('Password Reset Request',
                          sender=app.config['MAIL_USERNAME'],
                          recipients=[email])
            msg.body = f'''To reset your password, visit the following link:
{url_for('reset_token', token=user.reset_token, _external=True)}
This link will expire in 1 hour.
'''
            mail.send(msg)
            flash('A password reset email has been sent to your inbox.')
            return redirect(url_for('reset_password'))
        except Exception as e:
            db.session.rollback()
            flash('Failed to send email. Please try again later.')
            return redirect(url_for('reset_password'))

    return render_template('reset_password.html')

@app.route('/reset/<token>', methods=['GET', 'POST'])
def reset_token(token):
    try:
        email = serializer.loads(token, salt='password-reset-salt', max_age=3600)
    except:
        flash('Invalid or expired token.')
        return redirect(url_for('reset_password'))

    user = User.query.filter_by(email=email).first()
    if not user or user.reset_token != token:
        flash('Invalid or expired token.')
        return redirect(url_for('reset_password'))

    if request.method == 'POST':
        new_password = request.form['password']
        confirm_password = request.form['confirm_password']

        if new_password != confirm_password:
            flash('Passwords do not match.')
            return redirect(url_for('reset_token', token=token))

        user.set_password(new_password)
        user.reset_token = None
        user.token_expires = None
        db.session.commit()

        flash('Your password has been successfully reset.')
        return redirect(url_for('login'))  # Assume you have a login route

    return render_template('reset_token.html', token=token)

